+pub fn valid_shipment_transition(from: &str, to: &str) -> bool {
+    matches!(
+        (from, to),
+        ("created", "packed")
+            | ("packed", "shipped")
+            | ("shipped", "received")
+            | ("received", "completed")
+            | ("created", "canceled")
