+    let mut date: NaiveDate = start.date_naive();
+    let mut added = 0;
+    while added < business_days {
+        date = date.succ_opt().unwrap_or(date);
+        if !matches!(date.weekday(), Weekday::Sat | Weekday::Sun) {
+            added += 1;
+        }
+    }
