+    }
+    for row in sqlx::query(
+        "SELECT listing_id, COUNT(*) as count FROM favorites GROUP BY listing_id",
+    )
+    .fetch_all(pool)
+    .await?
+    {
+        let listing_id: String = row.get("listing_id");
+        *map.entry(listing_id).or_insert(0) += row.get::<i64, _>("count") * 2;
