+pub async fn approve_inventory_document(
+    State(state): State<AppState>,
+    Extension(current_user): Extension<Option<CurrentUser>>,
+    Path(document_id): Path<String>,
+) -> Result<Json<InventoryDocumentResponse>, AppError> {
