+fn relevance_score(card: &ListingCard, query: &str) -> i64 {
+    let query = query.to_lowercase();
+    let mut score = 0;
+    if card.title.to_lowercase().contains(&query) {
+        score += 5;
+    }
+    if card
+        .description
+        .clone()
+        .unwrap_or_default()
+        .to_lowercase()
+        .contains(&query)
+    {
+        score += 2;
+    }
+    if card
+        .category_slug
+        .clone()
+        .unwrap_or_default()
+        .to_lowercase()
+        .contains(&query)
+    {
+        score += 3;
+    }
+    score
+}
